def _check_unused_imports(self, tree):
        from collections import defaultdict
        importances = defaultdict(int)
        for node in ast.walk(tree):
            if isinstance(node, ast.Import):
                for alias in node.names:
                    importances[alias.name] += 1
            elif isinstance(node, ast.ImportFrom):
                for alias in node.names:
                    importances[f'{node.module}.{alias.name}'] += 1
        used_imports = set()
        for node in ast.walk(tree):
            if isinstance(node, ast.Name):
                used_imports.add(node.id)
        unused_imports = [imp for imp in importances if imp not in used_imports]
        return bool(unused_imports)

